//! Cherry-pick merge: assemble document content from line ranges and sections
//! across multiple versions.

use std::collections::HashMap;

// ── Input types ───────────────────────────────────────────────────────────────

#[derive(Debug, serde::Deserialize)]
#[serde(rename_all = "camelCase")]
struct SourceSpec {
    version_index: usize,
    #[serde(default)]
    line_ranges: Vec<[usize; 2]>,
    #[serde(default)]
    sections: Vec<String>,
}

#[derive(Debug, serde::Deserialize)]
#[serde(rename_all = "camelCase")]
struct SelectionSpec {
    sources: Vec<SourceSpec>,
    fill_from: Option<usize>,
}

// ── Output types ──────────────────────────────────────────────────────────────

#[derive(Debug, serde::Serialize)]
#[serde(rename_all = "camelCase")]
struct ProvenanceEntry {
    line_start: usize,
    line_end: usize,
    from_version: usize,
    #[serde(skip_serializing_if = "Option::is_none")]
    fill_from: Option<bool>,
}

#[derive(Debug, serde::Serialize)]
#[serde(rename_all = "camelCase")]
struct CherryPickResult {
    content: String,
    provenance: Vec<ProvenanceEntry>,
    stats: CherryPickStats,
}

#[derive(Debug, serde::Serialize)]
#[serde(rename_all = "camelCase")]
struct CherryPickStats {
    total_lines: usize,
    sources_used: usize,
    sections_extracted: usize,
    line_ranges_extracted: usize,
}

// ── Internal helpers ──────────────────────────────────────────────────────────

/// Find the 1-based inclusive line range [start, end] of a markdown section.
///
/// A section starts at the heading line that matches `heading` exactly (after
/// trimming) and runs to the next heading of the same or higher level, or end
/// of content.
///
/// Returns `None` when the heading is not found.
fn find_section_line_range(lines: &[&str], heading: &str) -> Option<(usize, usize)> {
    let heading_trimmed = heading.trim();
    let target_level = heading_trimmed.chars().take_while(|&c| c == '#').count();
    let mut section_start: Option<usize> = None;
    for (i, line) in lines.iter().enumerate() {
        let trimmed = line.trim();
        if let Some(start) = section_start {
            if trimmed.starts_with('#') {
                let level = trimmed.chars().take_while(|&c| c == '#').count();
                if level <= target_level {
                    return Some((start + 1, i));
                }
            }
        } else if trimmed == heading_trimmed {
            section_start = Some(i);
        }
    }
    section_start.map(|s| (s + 1, lines.len()))
}

/// Extract lines `start..=end` (1-based inclusive) joined by `\n`.
fn extract_section_content(lines: &[&str], start: usize, end: usize) -> String {
    lines[(start - 1)..end].join("\n")
}

/// Return every markdown heading that appears in `lines`, in order.
fn collect_section_headings(lines: &[&str]) -> Vec<String> {
    lines
        .iter()
        .filter(|l| l.trim().starts_with('#'))
        .map(|l| l.trim().to_string())
        .collect()
}

/// A contiguous block of output lines plus provenance metadata.
#[derive(Debug)]
struct ContentBlock {
    lines: Vec<String>,
    from_version: usize,
    is_fill: bool,
}

// ── Source collection ─────────────────────────────────────────────────────────

/// Parse all source specs into section claims and line-range blocks.
///
/// Returns `(sections_extracted, line_ranges_extracted)`.
fn collect_sources(
    selection: &SelectionSpec,
    versions: &HashMap<usize, String>,
    section_claims: &mut HashMap<String, (usize, String)>,
    line_range_blocks: &mut Vec<ContentBlock>,
) -> Result<(usize, usize), String> {
    let mut sections_extracted: usize = 0;
    let mut line_ranges_extracted: usize = 0;

    for source in &selection.sources {
        let ver_idx = source.version_index;
        let ver_content = versions
            .get(&ver_idx)
            .ok_or_else(|| format!("Version index {ver_idx} not found"))?;
        let ver_lines: Vec<&str> = ver_content.lines().collect();
        let ver_total = ver_lines.len();

        for heading in &source.sections {
            let normalized = heading.trim().to_string();
            let (sec_start, sec_end) = find_section_line_range(&ver_lines, &normalized)
                .ok_or_else(|| format!("Section '{normalized}' not found in version {ver_idx}"))?;
            if let Some((existing_ver, _)) = section_claims.get(&normalized) {
                return Err(format!(
                    "Section '{normalized}' claimed by multiple sources: \
                     version {existing_ver} and version {ver_idx}"
                ));
            }
            let content = extract_section_content(&ver_lines, sec_start, sec_end);
            section_claims.insert(normalized, (ver_idx, content));
            sections_extracted += 1;
        }

        collect_line_ranges(
            source,
            ver_idx,
            &ver_lines,
            ver_total,
            line_range_blocks,
            &mut line_ranges_extracted,
        )?;
    }

    Ok((sections_extracted, line_ranges_extracted))
}

/// Validate and collect line-range blocks for one source spec.
/// Overlap detection is scoped to this version's own coordinate space.
fn collect_line_ranges(
    source: &SourceSpec,
    ver_idx: usize,
    ver_lines: &[&str],
    ver_total: usize,
    out_blocks: &mut Vec<ContentBlock>,
    counter: &mut usize,
) -> Result<(), String> {
    let mut ver_assigned: HashMap<usize, usize> = HashMap::new();
    for range in &source.line_ranges {
        let [start, end] = *range;
        if start < 1 || end < start || end > ver_total {
            return Err(format!(
                "Line range [{start}, {end}] is out of bounds for version \
                 {ver_idx} ({ver_total} lines)"
            ));
        }
        for ln in start..=end {
            if let Some(&prev) = ver_assigned.get(&ln) {
                return Err(format!(
                    "Overlapping line ranges: line {ln} in version {ver_idx} \
                     is already assigned (range near line {prev})"
                ));
            }
            ver_assigned.insert(ln, start);
        }
        let block_lines: Vec<String> = ver_lines[(start - 1)..end]
            .iter()
            .map(|l| l.to_string())
            .collect();
        out_blocks.push(ContentBlock {
            lines: block_lines,
            from_version: ver_idx,
            is_fill: false,
        });
        *counter += 1;
    }
    Ok(())
}

// ── Assembly strategies ───────────────────────────────────────────────────────

/// Section-based assembly: walk the fillFrom document in heading order.
///
/// Claimed headings emit their full block content from the source version.
/// Sub-headings inside a claimed block are skipped (`claimed_parent_level`).
///
/// Fill (unclaimed) headings emit only the lines from that heading up to the
/// next heading at ANY level.  Sub-headings are processed individually so
/// claimed sub-headings can still be emitted from their source versions.
/// This prevents a broad fill heading from swallowing claimed sub-sections.
///
/// Appends line-range blocks after section content.
fn assemble_section_blocks(
    fill_lines: &[&str],
    fill_version_idx: usize,
    has_fill: bool,
    section_claims: &HashMap<String, (usize, String)>,
    line_range_blocks: Vec<ContentBlock>,
) -> Result<Vec<ContentBlock>, String> {
    let mut blocks: Vec<ContentBlock> = Vec::new();

    let heading_positions: Vec<usize> = fill_lines
        .iter()
        .enumerate()
        .filter(|(_, l)| l.trim().starts_with('#'))
        .map(|(i, _)| i)
        .collect();
    let first_heading_pos = heading_positions.first().copied();
    match first_heading_pos {
        Some(0) => {}
        Some(pos) => blocks.push(ContentBlock {
            lines: fill_lines[..pos].iter().map(|l| l.to_string()).collect(),
            from_version: fill_version_idx,
            is_fill: true,
        }),
        None if !fill_lines.is_empty() => blocks.push(ContentBlock {
            lines: fill_lines.iter().map(|l| l.to_string()).collect(),
            from_version: fill_version_idx,
            is_fill: true,
        }),
        None => {}
    }

    // Tracks level of the last CLAIMED heading. Sub-headings already embedded
    // inside the claimed block are skipped. Fill headings do NOT set this so
    // their sub-headings remain eligible for individual claiming.
    let mut claimed_parent_level: Option<usize> = None;

    for (pos_idx, &line_idx) in heading_positions.iter().enumerate() {
        let heading = fill_lines[line_idx].trim();
        let level = heading.chars().take_while(|&c| c == '#').count();

        // Skip sub-headings already contained in an emitted claimed block.
        if let Some(parent_level) = claimed_parent_level {
            if level > parent_level {
                continue;
            }
            claimed_parent_level = None;
        }

        if let Some((ver_idx, content)) = section_claims.get(heading) {
            blocks.push(ContentBlock {
                lines: content.lines().map(str::to_string).collect(),
                from_version: *ver_idx,
                is_fill: false,
            });
            claimed_parent_level = Some(level);
        } else if has_fill {
            // Emit only lines from this heading to the next heading (any level).
            // Sub-headings are processed individually so claimed ones still fire.
            let next_heading_line = heading_positions
                .get(pos_idx + 1)
                .copied()
                .unwrap_or(fill_lines.len());
            blocks.push(ContentBlock {
                lines: fill_lines[line_idx..next_heading_line]
                    .iter()
                    .map(|l| l.to_string())
                    .collect(),
                from_version: fill_version_idx,
                is_fill: true,
            });
        }
    }

    blocks.extend(line_range_blocks);
    Ok(blocks)
}

/// Positional (line-range-only) assembly: the original algorithm.
/// Builds a line-number assignment map, fills gaps, then emits in order.
fn assemble_line_range_blocks(
    selection: &SelectionSpec,
    versions: &HashMap<usize, String>,
    fill_version_idx: usize,
    fill_content: &str,
) -> Result<Vec<ContentBlock>, String> {
    let mut assigned: HashMap<usize, (usize, bool)> = HashMap::new();

    for source in &selection.sources {
        let ver_idx = source.version_index;
        let ver_content = versions
            .get(&ver_idx)
            .ok_or_else(|| format!("Version index {ver_idx} not found"))?;
        let ver_lines: Vec<&str> = ver_content.lines().collect();
        let ver_total = ver_lines.len();

        for range in &source.line_ranges {
            let [start, end] = *range;
            if start < 1 || end < start || end > ver_total {
                return Err(format!(
                    "Line range [{start}, {end}] is out of bounds for version \
                     {ver_idx} ({ver_total} lines)"
                ));
            }
            for ln in start..=end {
                if let Some(&(existing_ver, _)) = assigned.get(&ln) {
                    return Err(format!(
                        "Overlapping line ranges: lines {start}-{end} \
                         (version {ver_idx}) overlap at line {ln} already \
                         assigned from version {existing_ver}"
                    ));
                }
                assigned.insert(ln, (ver_idx, false));
            }
        }
    }

    if selection.fill_from.is_some() {
        for ln in 1..=fill_content.lines().count() {
            assigned.entry(ln).or_insert((fill_version_idx, true));
        }
    }

    let ver_line_cache: HashMap<usize, Vec<String>> = versions
        .iter()
        .map(|(&idx, c)| (idx, c.lines().map(str::to_string).collect()))
        .collect();

    let mut sorted: Vec<usize> = assigned.keys().copied().collect();
    sorted.sort_unstable();

    let mut blocks: Vec<ContentBlock> = Vec::new();
    let mut current: Option<ContentBlock> = None;

    for &ln in &sorted {
        let &(ver_idx, is_fill) = assigned
            .get(&ln)
            .ok_or_else(|| format!("Internal error: line {ln} missing from map"))?;
        let ver_lines = ver_line_cache
            .get(&ver_idx)
            .ok_or_else(|| format!("Internal error: version {ver_idx} missing from cache"))?;
        let line_str = ver_lines
            .get(ln - 1)
            .ok_or_else(|| format!("Internal error: line {ln} out of range for v{ver_idx}"))?;

        match current.as_mut() {
            Some(b) if b.from_version == ver_idx && b.is_fill == is_fill => {
                b.lines.push(line_str.clone());
            }
            _ => {
                if let Some(b) = current.take() {
                    blocks.push(b);
                }
                current = Some(ContentBlock {
                    lines: vec![line_str.clone()],
                    from_version: ver_idx,
                    is_fill,
                });
            }
        }
    }
    if let Some(b) = current {
        blocks.push(b);
    }
    Ok(blocks)
}

// ── Output builder ────────────────────────────────────────────────────────────

/// Convert `ContentBlock`s into a final content string and provenance list.
fn build_output(blocks: &[ContentBlock], fill_content: &str) -> (String, Vec<ProvenanceEntry>) {
    let mut all_lines: Vec<String> = Vec::new();
    let mut provenance: Vec<ProvenanceEntry> = Vec::new();

    for block in blocks {
        if block.lines.is_empty() {
            continue;
        }
        let start_line = all_lines.len() + 1;
        all_lines.extend(block.lines.iter().cloned());
        provenance.push(ProvenanceEntry {
            line_start: start_line,
            line_end: all_lines.len(),
            from_version: block.from_version,
            fill_from: if block.is_fill { Some(true) } else { None },
        });
    }

    let mut content = all_lines.join("\n");
    if fill_content.ends_with('\n') && !content.is_empty() {
        content.push('\n');
    }
    (content, provenance)
}

// ── Public API ────────────────────────────────────────────────────────────────

/// Merge content from multiple versions by cherry-picking specific line ranges
/// and/or markdown sections.
///
/// # Arguments
/// - `base`: base version content (usually v1). Inserted as version index 0 if
///   key `"0"` is absent from `versions_json`.
/// - `versions_json`: JSON object mapping version index (string key) to full
///   content, e.g. `{"0":"...", "1":"...", "2":"..."}`.
/// - `selection_json`: JSON object with a `sources` array and an optional
///   `fillFrom` index. Each source has `versionIndex` and either `lineRanges`
///   (array of `[start, end]` 1-based inclusive pairs) or `sections` (array of
///   markdown heading strings).
///
/// # Returns
/// JSON string with `content`, `provenance`, and `stats` fields on success.
///
/// # Errors
/// - `"Version index N not found"` — `versionIndex` references missing version.
/// - `"Section 'X' not found in version N"` — section heading not present.
/// - `"Section 'X' claimed by multiple sources"` — two sources pick same section.
/// - `"Overlapping line ranges: ..."` — two selections assign the same line.
pub fn cherry_pick_merge(
    base: &str,
    versions_json: &str,
    selection_json: &str,
) -> Result<String, String> {
    let versions_raw: HashMap<String, String> =
        serde_json::from_str(versions_json).map_err(|e| format!("Invalid versions JSON: {e}"))?;
    let selection: SelectionSpec =
        serde_json::from_str(selection_json).map_err(|e| format!("Invalid selection JSON: {e}"))?;

    let mut versions: HashMap<usize, String> = HashMap::new();
    for (k, v) in &versions_raw {
        let idx: usize = k
            .parse()
            .map_err(|_| format!("Version key '{k}' is not a valid integer"))?;
        versions.insert(idx, v.clone());
    }
    versions.entry(0).or_insert_with(|| base.to_string());

    let fill_version_idx = selection.fill_from.unwrap_or(0);
    let fill_content = versions
        .get(&fill_version_idx)
        .ok_or_else(|| format!("Version index {fill_version_idx} not found"))?
        .clone();

    let mut section_claims: HashMap<String, (usize, String)> = HashMap::new();
    let mut line_range_blocks: Vec<ContentBlock> = Vec::new();
    let (sections_extracted, line_ranges_extracted) = collect_sources(
        &selection,
        &versions,
        &mut section_claims,
        &mut line_range_blocks,
    )?;

    let has_sections =
        !section_claims.is_empty() || selection.sources.iter().any(|s| !s.sections.is_empty());

    let blocks: Vec<ContentBlock> = if has_sections {
        let fill_lines: Vec<&str> = fill_content.lines().collect();
        assemble_section_blocks(
            &fill_lines,
            fill_version_idx,
            selection.fill_from.is_some(),
            &section_claims,
            line_range_blocks,
        )?
    } else {
        assemble_line_range_blocks(&selection, &versions, fill_version_idx, &fill_content)?
    };

    let (content, provenance) = build_output(&blocks, &fill_content);
    let total_lines = content.lines().count();

    serde_json::to_string(&CherryPickResult {
        content,
        provenance,
        stats: CherryPickStats {
            total_lines,
            sources_used: selection.sources.len(),
            sections_extracted,
            line_ranges_extracted,
        },
    })
    .map_err(|e| format!("Serialization failed: {e}"))
}

#[cfg(test)]
mod tests {
    use super::*;

    fn make_versions_json(versions: &[(usize, &str)]) -> String {
        let map: serde_json::Map<String, serde_json::Value> = versions
            .iter()
            .map(|(i, c)| (i.to_string(), serde_json::Value::String(c.to_string())))
            .collect();
        serde_json::to_string(&map).unwrap()
    }

    fn make_selection(sources: &[serde_json::Value], fill_from: Option<usize>) -> String {
        let mut obj = serde_json::json!({ "sources": sources });
        if let Some(idx) = fill_from {
            obj["fillFrom"] = serde_json::json!(idx);
        }
        serde_json::to_string(&obj).unwrap()
    }

    fn parse(json: &str) -> serde_json::Value {
        serde_json::from_str(json).unwrap()
    }

    // ── Line range tests ──────────────────────────────────────────

    #[test]
    fn test_line_range_basic() {
        let v0 = "a\nb\nc\nd\ne\n";
        let v1 = "A\nB\nC\nD\nE\n";
        let vj = make_versions_json(&[(0, v0), (1, v1)]);
        let sel = make_selection(
            &[
                serde_json::json!({ "versionIndex": 0, "lineRanges": [[1, 2]] }),
                serde_json::json!({ "versionIndex": 1, "lineRanges": [[4, 5]] }),
            ],
            Some(0),
        );
        let r = parse(&cherry_pick_merge(v0, &vj, &sel).unwrap());
        let lines: Vec<&str> = r["content"].as_str().unwrap().lines().collect();
        assert_eq!(lines, ["a", "b", "c", "D", "E"]);
        assert_eq!(r["stats"]["totalLines"], 5);
        assert_eq!(r["stats"]["lineRangesExtracted"], 2);
        assert_eq!(r["stats"]["sectionsExtracted"], 0);
    }

    #[test]
    fn test_no_fill_only_explicit() {
        let v0 = "a\nb\nc\n";
        let v1 = "X\nY\nZ\n";
        let vj = make_versions_json(&[(0, v0), (1, v1)]);
        let sel = make_selection(
            &[serde_json::json!({ "versionIndex": 1, "lineRanges": [[2, 2]] })],
            None,
        );
        let r = parse(&cherry_pick_merge(v0, &vj, &sel).unwrap());
        let lines: Vec<&str> = r["content"].as_str().unwrap().lines().collect();
        assert_eq!(lines, ["Y"]);
        assert_eq!(r["stats"]["totalLines"], 1);
    }

    // ── Section tests ─────────────────────────────────────────────

    #[test]
    fn test_multiple_sections_from_different_versions() {
        let v0 = "# Alpha\nalpha v0\n# Beta\nbeta v0\n# Gamma\ngamma v0\n";
        let v1 = "# Alpha\nalpha v1\n# Beta\nbeta v1\n# Gamma\ngamma v1\n";
        let v2 = "# Alpha\nalpha v2\n# Beta\nbeta v2\n# Gamma\ngamma v2\n";
        let vj = make_versions_json(&[(0, v0), (1, v1), (2, v2)]);
        let sel = make_selection(
            &[
                serde_json::json!({ "versionIndex": 1, "sections": ["# Beta"] }),
                serde_json::json!({ "versionIndex": 2, "sections": ["# Gamma"] }),
            ],
            Some(0),
        );
        let r = parse(&cherry_pick_merge(v0, &vj, &sel).unwrap());
        let c = r["content"].as_str().unwrap();
        assert!(c.contains("alpha v0") && c.contains("beta v1") && c.contains("gamma v2"));
        assert_eq!(r["stats"]["sectionsExtracted"], 2);
        assert_eq!(r["stats"]["sourcesUsed"], 2);
    }

    // ── Provenance tests ──────────────────────────────────────────

    #[test]
    fn test_provenance_metadata() {
        let v0 = "a\nb\nc\nd\ne\n";
        let v1 = "A\nB\nC\nD\nE\n";
        let vj = make_versions_json(&[(0, v0), (1, v1)]);
        let sel = make_selection(
            &[
                serde_json::json!({ "versionIndex": 0, "lineRanges": [[1, 2]] }),
                serde_json::json!({ "versionIndex": 1, "lineRanges": [[4, 5]] }),
            ],
            Some(0),
        );
        let r = parse(&cherry_pick_merge(v0, &vj, &sel).unwrap());
        let prov = r["provenance"].as_array().unwrap();
        assert!(prov.iter().any(|p| p["fromVersion"] == 0
            && p["lineStart"] == 1
            && p["lineEnd"] == 2
            && p["fillFrom"].is_null()));
        assert!(
            prov.iter()
                .any(|p| p["fromVersion"] == 0 && p["fillFrom"] == true)
        );
        assert!(prov.iter().any(|p| p["fromVersion"] == 1));
    }

    // ── Error tests ───────────────────────────────────────────────

    #[test]
    fn test_overlapping_line_ranges_error() {
        let v0 = "a\nb\nc\nd\ne\n";
        let vj = make_versions_json(&[(0, v0)]);
        let sel = make_selection(
            &[
                serde_json::json!({ "versionIndex": 0, "lineRanges": [[2, 4]] }),
                serde_json::json!({ "versionIndex": 0, "lineRanges": [[3, 5]] }),
            ],
            None,
        );
        assert!(
            cherry_pick_merge(v0, &vj, &sel)
                .unwrap_err()
                .contains("Overlapping line ranges")
        );
    }

    #[test]
    fn test_version_not_found_error() {
        let v0 = "a\nb\nc\n";
        let vj = make_versions_json(&[(0, v0)]);
        let sel = make_selection(
            &[serde_json::json!({ "versionIndex": 99, "lineRanges": [[1, 2]] })],
            None,
        );
        assert!(
            cherry_pick_merge(v0, &vj, &sel)
                .unwrap_err()
                .contains("Version index 99 not found")
        );
    }

    #[test]
    fn test_section_not_found_error() {
        let v0 = "# Intro\nHello\n# Footer\nBye\n";
        let vj = make_versions_json(&[(0, v0)]);
        let sel = make_selection(
            &[serde_json::json!({ "versionIndex": 0, "sections": ["# Nonexistent"] })],
            None,
        );
        assert!(
            cherry_pick_merge(v0, &vj, &sel)
                .unwrap_err()
                .contains("Section '# Nonexistent' not found")
        );
    }

    // ── New tests: per-version coordinate spaces ──────────────────

    /// Core regression: v2 expands Section 1, v3 expands Section 2 — different
    /// line counts across versions must not cause overlap errors or wrong fills.
    #[test]
    fn test_multi_version_sections_different_line_counts() {
        let base = "# Section 1\nbase s1\n# Section 2\nbase s2\n# Section 3\nbase s3\n";
        let v2 = "# Section 1\nv2 s1 line1\nv2 s1 line2\nv2 s1 line3\n# Section 2\nv2 s2\n# Section 3\nv2 s3\n";
        let v3 = "# Section 1\nv3 s1\n# Section 2\nv3 s2 line1\nv3 s2 line2\n# Section 3\nv3 s3\n";
        let vj = make_versions_json(&[(0, base), (2, v2), (3, v3)]);
        let sel = make_selection(
            &[
                serde_json::json!({ "versionIndex": 2, "sections": ["# Section 1"] }),
                serde_json::json!({ "versionIndex": 3, "sections": ["# Section 2"] }),
            ],
            Some(0),
        );
        let r = parse(&cherry_pick_merge(base, &vj, &sel).expect("merge must succeed"));
        let c = r["content"].as_str().unwrap();
        assert!(c.contains("v2 s1 line1") && c.contains("v2 s1 line3"));
        assert!(c.contains("v3 s2 line1") && c.contains("v3 s2 line2"));
        assert!(c.contains("base s3") && !c.contains("v3 s1") && !c.contains("v2 s2"));
        assert_eq!(r["stats"]["sectionsExtracted"], 2);
    }

    #[test]
    fn test_duplicate_section_claim_error() {
        let v0 = "# Alpha\nalpha v0\n# Beta\nbeta v0\n";
        let v1 = "# Alpha\nalpha v1\n# Beta\nbeta v1\n";
        let v2 = "# Alpha\nalpha v2\n# Beta\nbeta v2\n";
        let vj = make_versions_json(&[(0, v0), (1, v1), (2, v2)]);
        let sel = make_selection(
            &[
                serde_json::json!({ "versionIndex": 1, "sections": ["# Alpha"] }),
                serde_json::json!({ "versionIndex": 2, "sections": ["# Alpha"] }),
            ],
            Some(0),
        );
        assert!(
            cherry_pick_merge(v0, &vj, &sel)
                .unwrap_err()
                .contains("claimed by multiple sources")
        );
    }

    #[test]
    fn test_line_ranges_per_version_coordinate_space() {
        let v0 = "line1\nline2\nline3\nline4\nline5\n";
        let v1 = "LINE1\nLINE2\nLINE3\nLINE4\nLINE5\n";
        let vj = make_versions_json(&[(0, v0), (1, v1)]);
        let sel = make_selection(
            &[serde_json::json!({ "versionIndex": 1, "lineRanges": [[3, 4]] })],
            Some(0),
        );
        let r = parse(&cherry_pick_merge(v0, &vj, &sel).unwrap());
        let lines: Vec<&str> = r["content"].as_str().unwrap().lines().collect();
        assert_eq!(lines, ["line1", "line2", "LINE3", "LINE4", "line5"]);
    }

    /// 5-section merge: B from v2, D from v4, fill from v1.
    /// Output must be A(v1) B(v2) C(v1) D(v4) E(v1) — no duplication.
    #[test]
    fn test_five_section_no_duplication() {
        let v1 = "# A\nA v1\n# B\nB v1\n# C\nC v1\n# D\nD v1\n# E\nE v1\n";
        let v2 = "# A\nA v2\n# B\nB v2\n# C\nC v2\n# D\nD v2\n# E\nE v2\n";
        let v4 = "# A\nA v4\n# B\nB v4\n# C\nC v4\n# D\nD v4\n# E\nE v4\n";
        let vj = make_versions_json(&[(1, v1), (2, v2), (4, v4)]);
        let sel = make_selection(
            &[
                serde_json::json!({ "versionIndex": 2, "sections": ["# B"] }),
                serde_json::json!({ "versionIndex": 4, "sections": ["# D"] }),
            ],
            Some(1),
        );
        let r = parse(&cherry_pick_merge(v1, &vj, &sel).unwrap());
        let c = r["content"].as_str().unwrap();
        let hdrs: Vec<&str> = c.lines().filter(|l| l.starts_with('#')).collect();
        assert_eq!(hdrs, ["# A", "# B", "# C", "# D", "# E"]);
        assert!(c.contains("A v1") && c.contains("B v2") && c.contains("C v1"));
        assert!(c.contains("D v4") && c.contains("E v1"));
        assert!(!c.contains("B v1") && !c.contains("D v1"));
        let (pa, pb, pc, pd, pe) = (
            c.find("A v1").unwrap(),
            c.find("B v2").unwrap(),
            c.find("C v1").unwrap(),
            c.find("D v4").unwrap(),
            c.find("E v1").unwrap(),
        );
        assert!(pa < pb && pb < pc && pc < pd && pd < pe);
    }

    /// Claiming a parent section must not also emit its child headings from fill.
    /// Regression: ## Setup claimed from v1 must not repeat ### Install / ### Config
    /// that are already inside the claimed block.
    #[test]
    fn test_claimed_parent_does_not_duplicate_children() {
        let base =
            "## Setup\n### Install\ninstall base\n### Config\nconfig base\n## Usage\nusage base\n";
        let v1 = "## Setup\n### Install\ninstall v1\n### Config\nconfig v1\n## Usage\nusage v1\n";
        let vj = make_versions_json(&[(0, base), (1, v1)]);
        let sel = make_selection(
            &[serde_json::json!({ "versionIndex": 1, "sections": ["## Setup"] })],
            Some(0),
        );
        let r = parse(&cherry_pick_merge(base, &vj, &sel).unwrap());
        let c = r["content"].as_str().unwrap();
        // Each heading must appear exactly once
        let setup_count = c.matches("## Setup").count();
        let install_count = c.matches("### Install").count();
        let config_count = c.matches("### Config").count();
        assert_eq!(setup_count, 1, "## Setup must appear exactly once");
        assert_eq!(install_count, 1, "### Install must appear exactly once");
        assert_eq!(config_count, 1, "### Config must appear exactly once");
        // Content is correct version
        assert!(c.contains("install v1"), "### Install content from v1");
        assert!(c.contains("config v1"), "### Config content from v1");
        assert!(c.contains("usage base"), "## Usage content from fill");
        assert!(!c.contains("install base"), "fill install must not appear");
        assert!(!c.contains("config base"), "fill config must not appear");
        // Order: Setup before Usage
        assert!(c.find("## Setup").unwrap() < c.find("## Usage").unwrap());
    }

    /// Mixed mode: section source + line-range source in the same selection.
    #[test]
    fn test_mixed_sections_and_line_ranges() {
        let base = "# Intro\nintro base\n# Body\nbody base\n# Footer\nfooter base\n";
        let v1 = "# Intro\nintro v1\n# Body\nbody v1\n# Footer\nfooter v1\n";
        let v2 = "EXTRA_LINE_1\nEXTRA_LINE_2\nEXTRA_LINE_3\n";
        let vj = make_versions_json(&[(0, base), (1, v1), (2, v2)]);
        let sel = make_selection(
            &[
                serde_json::json!({ "versionIndex": 1, "sections": ["# Body"] }),
                serde_json::json!({ "versionIndex": 2, "lineRanges": [[1, 2]] }),
            ],
            Some(0),
        );
        let r = parse(&cherry_pick_merge(base, &vj, &sel).unwrap());
        let c = r["content"].as_str().unwrap();
        assert!(c.contains("intro base") && c.contains("body v1") && c.contains("footer base"));
        assert!(
            c.contains("EXTRA_LINE_1") && c.contains("EXTRA_LINE_2") && !c.contains("EXTRA_LINE_3")
        );
        assert_eq!(r["stats"]["sectionsExtracted"], 1);
        assert_eq!(r["stats"]["lineRangesExtracted"], 1);
    }
}

//! Consensus and approval workflow evaluation.
//!
//! Pure functions for multi-agent review/approval workflows.
//! No storage, no side effects -- just evaluation logic.
//!
//! Accepts and returns JSON for WASM compatibility. Native callers
//! can use the struct-based variants directly.

use serde::{Deserialize, Serialize};
use std::collections::{HashMap, HashSet};

#[cfg(feature = "wasm")]
use wasm_bindgen::prelude::*;

/// A single review from an agent.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct Review {
    /// Agent that submitted the review.
    pub reviewer_id: String,
    /// Current status: PENDING, APPROVED, REJECTED, STALE.
    pub status: String,
    /// Timestamp of the review action (ms since epoch).
    pub timestamp: f64,
    /// Reason or comment provided with the review.
    #[serde(skip_serializing_if = "Option::is_none")]
    pub reason: Option<String>,
    /// Version number the review applies to.
    pub at_version: u32,
}

/// Policy governing how approvals are evaluated.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct ApprovalPolicy {
    /// Minimum number of approvals required (absolute count).
    /// Ignored when `required_percentage` is set (> 0).
    pub required_count: u32,
    /// If true, all allowed reviewers must approve (overrides count/percentage).
    pub require_unanimous: bool,
    /// Agent IDs allowed to review. Empty means anyone can review.
    pub allowed_reviewer_ids: Vec<String>,
    /// Auto-expire reviews older than this (ms). 0 means no timeout.
    pub timeout_ms: f64,
    /// Percentage of effective reviewers required to approve (0-100).
    /// 0 means use `required_count` instead. When > 0, the required count
    /// is computed as `ceil(percentage * effective_reviewer_count / 100)`.
    #[serde(default)]
    pub required_percentage: u32,
}

/// Result of evaluating reviews against a policy.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct ApprovalResult {
    /// Whether the approval threshold is met.
    pub approved: bool,
    /// Reviewers that have approved.
    pub approved_by: Vec<String>,
    /// Reviewers that have rejected.
    pub rejected_by: Vec<String>,
    /// Reviewers that are still pending.
    pub pending_from: Vec<String>,
    /// Reviewers whose reviews are stale.
    pub stale_from: Vec<String>,
    /// Human-readable summary.
    pub reason: String,
}

/// Evaluate reviews against an approval policy (native API).
///
/// Filters out stale and timed-out reviews, then checks whether the
/// remaining approvals meet the policy threshold.
pub fn evaluate_approvals_native(
    reviews: &[Review],
    policy: &ApprovalPolicy,
    current_version: u32,
    now: f64,
) -> ApprovalResult {
    let mut approved_by = Vec::new();
    let mut rejected_by = Vec::new();
    let mut pending_from = Vec::new();
    let mut stale_from = Vec::new();

    // Determine effective reviewers
    let effective_reviewers: Vec<String> = if !policy.allowed_reviewer_ids.is_empty() {
        policy.allowed_reviewer_ids.clone()
    } else {
        let mut seen = HashSet::new();
        reviews
            .iter()
            .filter(|r| seen.insert(r.reviewer_id.clone()))
            .map(|r| r.reviewer_id.clone())
            .collect()
    };

    // Keep latest review per reviewer
    let mut review_map: HashMap<&str, &Review> = HashMap::new();
    for review in reviews {
        let dominated = match review_map.get(review.reviewer_id.as_str()) {
            None => true,
            Some(existing) => review.timestamp > existing.timestamp,
        };
        if dominated {
            review_map.insert(&review.reviewer_id, review);
        }
    }

    for reviewer_id in &effective_reviewers {
        let Some(review) = review_map.get(reviewer_id.as_str()) else {
            pending_from.push(reviewer_id.clone());
            continue;
        };

        // Stale if review was for an older version
        if review.at_version < current_version {
            stale_from.push(reviewer_id.clone());
            continue;
        }

        // Stale if review timed out
        if policy.timeout_ms > 0.0 && (now - review.timestamp) > policy.timeout_ms {
            stale_from.push(reviewer_id.clone());
            continue;
        }

        match review.status.to_uppercase().as_str() {
            "APPROVED" => approved_by.push(reviewer_id.clone()),
            "REJECTED" => rejected_by.push(reviewer_id.clone()),
            "STALE" => stale_from.push(reviewer_id.clone()),
            _ => pending_from.push(reviewer_id.clone()),
        }
    }

    // Evaluate threshold
    let (approved, reason) = if !rejected_by.is_empty() {
        (false, format!("Rejected by {}", rejected_by.join(", ")))
    } else if policy.require_unanimous {
        let all_approved = approved_by.len() == effective_reviewers.len()
            && pending_from.is_empty()
            && stale_from.is_empty();
        let reason = if all_approved {
            format!(
                "Unanimous approval ({}/{})",
                approved_by.len(),
                effective_reviewers.len()
            )
        } else {
            format!(
                "Awaiting unanimous approval ({}/{})",
                approved_by.len(),
                effective_reviewers.len()
            )
        };
        (all_approved, reason)
    } else {
        // Compute effective threshold: percentage overrides count when > 0
        let threshold = if policy.required_percentage > 0 {
            let pct = policy.required_percentage.min(100) as f64 / 100.0;
            (pct * effective_reviewers.len() as f64).ceil() as u32
        } else {
            policy.required_count
        };
        let met = approved_by.len() as u32 >= threshold;
        let threshold_label = if policy.required_percentage > 0 {
            format!("{}% = {}", policy.required_percentage, threshold)
        } else {
            format!("{}", threshold)
        };
        let reason = if met {
            format!(
                "Approved ({}/{} required)",
                approved_by.len(),
                threshold_label
            )
        } else {
            let remaining = threshold.saturating_sub(approved_by.len() as u32);
            format!(
                "Needs {} more approval(s) ({}/{} required)",
                remaining,
                approved_by.len(),
                threshold_label
            )
        };
        (met, reason)
    };

    ApprovalResult {
        approved,
        approved_by,
        rejected_by,
        pending_from,
        stale_from,
        reason,
    }
}

/// Mark reviews as stale when a document version changes.
///
/// Returns a new vector with updated review statuses.
pub fn mark_stale_reviews_native(reviews: &[Review], current_version: u32) -> Vec<Review> {
    reviews
        .iter()
        .map(|r| {
            if r.at_version < current_version && r.status.to_uppercase() != "STALE" {
                Review {
                    status: "STALE".to_string(),
                    ..r.clone()
                }
            } else {
                r.clone()
            }
        })
        .collect()
}

// ── WASM entry points (JSON I/O) ──────────────────────────────

/// Evaluate reviews against a policy. All inputs and output are JSON strings.
///
/// Input `reviews_json`: `[{"reviewerId":"...","status":"APPROVED","timestamp":123,"atVersion":1}]`
/// Input `policy_json`: `{"requiredCount":1,"requireUnanimous":false,"allowedReviewerIds":[],"timeoutMs":0}`
///
/// Returns a JSON string matching the TypeScript `ApprovalResult` interface.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn evaluate_approvals(
    reviews_json: &str,
    policy_json: &str,
    current_version: u32,
    now_ms: f64,
) -> Result<String, String> {
    let reviews: Vec<Review> =
        serde_json::from_str(reviews_json).map_err(|e| format!("Invalid reviews JSON: {e}"))?;
    let policy: ApprovalPolicy =
        serde_json::from_str(policy_json).map_err(|e| format!("Invalid policy JSON: {e}"))?;

    let result = evaluate_approvals_native(&reviews, &policy, current_version, now_ms);
    serde_json::to_string(&result).map_err(|e| format!("Serialization failed: {e}"))
}

/// Mark reviews as stale for the given version. JSON I/O for WASM.
///
/// Returns a JSON array of updated reviews.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn mark_stale_reviews(reviews_json: &str, current_version: u32) -> Result<String, String> {
    let reviews: Vec<Review> =
        serde_json::from_str(reviews_json).map_err(|e| format!("Invalid reviews JSON: {e}"))?;

    let result = mark_stale_reviews_native(&reviews, current_version);
    serde_json::to_string(&result).map_err(|e| format!("Serialization failed: {e}"))
}

#[cfg(test)]
mod tests {
    use super::*;

    fn default_policy() -> ApprovalPolicy {
        ApprovalPolicy {
            required_count: 1,
            require_unanimous: false,
            allowed_reviewer_ids: vec![],
            timeout_ms: 0.0,
            required_percentage: 0,
        }
    }

    fn review(id: &str, status: &str, version: u32) -> Review {
        Review {
            reviewer_id: id.to_string(),
            status: status.to_string(),
            timestamp: 1_000_000.0,
            reason: None,
            at_version: version,
        }
    }

    #[test]
    fn test_single_approval_meets_default_policy() {
        let reviews = vec![review("agent-1", "APPROVED", 1)];
        let result = evaluate_approvals_native(&reviews, &default_policy(), 1, 2_000_000.0);
        assert!(result.approved);
        assert_eq!(result.approved_by, vec!["agent-1"]);
    }

    #[test]
    fn test_no_reviews_pending() {
        let policy = ApprovalPolicy {
            allowed_reviewer_ids: vec!["agent-1".to_string()],
            ..default_policy()
        };
        let result = evaluate_approvals_native(&[], &policy, 1, 2_000_000.0);
        assert!(!result.approved);
        assert_eq!(result.pending_from, vec!["agent-1"]);
    }

    #[test]
    fn test_rejection_overrides_approval() {
        let reviews = vec![
            review("agent-1", "APPROVED", 1),
            review("agent-2", "REJECTED", 1),
        ];
        let policy = ApprovalPolicy {
            required_count: 1,
            ..default_policy()
        };
        let result = evaluate_approvals_native(&reviews, &policy, 1, 2_000_000.0);
        assert!(!result.approved);
        assert!(result.reason.contains("Rejected"));
    }

    #[test]
    fn test_stale_review_for_old_version() {
        let reviews = vec![review("agent-1", "APPROVED", 1)];
        let result = evaluate_approvals_native(&reviews, &default_policy(), 2, 2_000_000.0);
        assert!(!result.approved);
        assert_eq!(result.stale_from, vec!["agent-1"]);
    }

    #[test]
    fn test_timed_out_review() {
        let reviews = vec![Review {
            reviewer_id: "agent-1".to_string(),
            status: "APPROVED".to_string(),
            timestamp: 1_000_000.0,
            reason: None,
            at_version: 1,
        }];
        let policy = ApprovalPolicy {
            timeout_ms: 500_000.0,
            ..default_policy()
        };
        // now is 2_000_000, review was at 1_000_000, timeout is 500_000
        let result = evaluate_approvals_native(&reviews, &policy, 1, 2_000_000.0);
        assert!(!result.approved);
        assert_eq!(result.stale_from, vec!["agent-1"]);
    }

    #[test]
    fn test_unanimous_policy() {
        let policy = ApprovalPolicy {
            required_count: 2,
            require_unanimous: true,
            allowed_reviewer_ids: vec!["agent-1".to_string(), "agent-2".to_string()],
            timeout_ms: 0.0,
            required_percentage: 0,
        };

        // Only one approved
        let reviews = vec![review("agent-1", "APPROVED", 1)];
        let result = evaluate_approvals_native(&reviews, &policy, 1, 2_000_000.0);
        assert!(!result.approved);
        assert!(result.reason.contains("Awaiting unanimous"));

        // Both approved
        let reviews = vec![
            review("agent-1", "APPROVED", 1),
            review("agent-2", "APPROVED", 1),
        ];
        let result = evaluate_approvals_native(&reviews, &policy, 1, 2_000_000.0);
        assert!(result.approved);
        assert!(result.reason.contains("Unanimous"));
    }

    #[test]
    fn test_latest_review_wins() {
        let reviews = vec![
            Review {
                reviewer_id: "agent-1".to_string(),
                status: "REJECTED".to_string(),
                timestamp: 1_000_000.0,
                reason: None,
                at_version: 1,
            },
            Review {
                reviewer_id: "agent-1".to_string(),
                status: "APPROVED".to_string(),
                timestamp: 2_000_000.0,
                reason: None,
                at_version: 1,
            },
        ];
        let result = evaluate_approvals_native(&reviews, &default_policy(), 1, 3_000_000.0);
        assert!(result.approved);
        assert_eq!(result.approved_by, vec!["agent-1"]);
    }

    #[test]
    fn test_mark_stale_reviews() {
        let reviews = vec![
            review("agent-1", "APPROVED", 1),
            review("agent-2", "APPROVED", 2),
        ];
        let result = mark_stale_reviews_native(&reviews, 2);
        assert_eq!(result[0].status, "STALE");
        assert_eq!(result[1].status, "APPROVED");
    }

    #[test]
    fn test_wasm_evaluate_approvals() {
        let reviews_json =
            r#"[{"reviewerId":"agent-1","status":"APPROVED","timestamp":1000000,"atVersion":1}]"#;
        let policy_json =
            r#"{"requiredCount":1,"requireUnanimous":false,"allowedReviewerIds":[],"timeoutMs":0}"#;
        let result_json = evaluate_approvals(reviews_json, policy_json, 1, 2_000_000.0).unwrap();
        let result: ApprovalResult = serde_json::from_str(&result_json).unwrap();
        assert!(result.approved);
    }

    #[test]
    fn test_wasm_mark_stale() {
        let reviews_json =
            r#"[{"reviewerId":"agent-1","status":"APPROVED","timestamp":1000000,"atVersion":1}]"#;
        let result_json = mark_stale_reviews(reviews_json, 2).unwrap();
        let result: Vec<Review> = serde_json::from_str(&result_json).unwrap();
        assert_eq!(result[0].status, "STALE");
    }

    #[test]
    fn test_percentage_threshold_51_percent() {
        // 51% of 10 reviewers = ceil(5.1) = 6 required
        let ids: Vec<String> = (1..=10).map(|i| format!("agent-{i}")).collect();
        let policy = ApprovalPolicy {
            required_count: 0,
            require_unanimous: false,
            allowed_reviewer_ids: ids,
            timeout_ms: 0.0,
            required_percentage: 51,
        };

        // 5 approved — not enough (need 6)
        let reviews: Vec<Review> = (1..=5)
            .map(|i| review(&format!("agent-{i}"), "APPROVED", 1))
            .collect();
        let result = evaluate_approvals_native(&reviews, &policy, 1, 2_000_000.0);
        assert!(!result.approved, "5/10 should not meet 51%");
        assert!(result.reason.contains("51%"));

        // 6 approved — enough
        let reviews: Vec<Review> = (1..=6)
            .map(|i| review(&format!("agent-{i}"), "APPROVED", 1))
            .collect();
        let result = evaluate_approvals_native(&reviews, &policy, 1, 2_000_000.0);
        assert!(result.approved, "6/10 should meet 51%");
    }

    #[test]
    fn test_percentage_threshold_20_percent() {
        // 20% of 5 reviewers = ceil(1.0) = 1 required
        let policy = ApprovalPolicy {
            required_count: 0,
            require_unanimous: false,
            allowed_reviewer_ids: vec![
                "a1".into(),
                "a2".into(),
                "a3".into(),
                "a4".into(),
                "a5".into(),
            ],
            timeout_ms: 0.0,
            required_percentage: 20,
        };

        let reviews = vec![review("a1", "APPROVED", 1)];
        let result = evaluate_approvals_native(&reviews, &policy, 1, 2_000_000.0);
        assert!(result.approved, "1/5 should meet 20%");
    }

    #[test]
    fn test_percentage_overrides_count() {
        // required_count is 10 but percentage says 20% of 5 = 1
        let policy = ApprovalPolicy {
            required_count: 10,
            require_unanimous: false,
            allowed_reviewer_ids: vec![
                "a1".into(),
                "a2".into(),
                "a3".into(),
                "a4".into(),
                "a5".into(),
            ],
            timeout_ms: 0.0,
            required_percentage: 20,
        };

        let reviews = vec![review("a1", "APPROVED", 1)];
        let result = evaluate_approvals_native(&reviews, &policy, 1, 2_000_000.0);
        assert!(result.approved, "percentage should override count");
    }
}

//! Line-based diff computation using LCS (Longest Common Subsequence).
//!
//! Provides both summary-only ([`compute_diff`]) and structured
//! ([`structured_diff`]) diff output. The structured variant is the
//! single source of truth for diff display across frontend, backend,
//! and CLI consumers.

#[cfg(feature = "wasm")]
use wasm_bindgen::prelude::*;

use crate::calculate_tokens;

// ── Summary Diff ───────────────────────────────────────────────

/// Result of computing a line-based diff between two texts.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
#[derive(Debug, Clone)]
pub struct DiffResult {
    added_lines: u32,
    removed_lines: u32,
    added_tokens: u32,
    removed_tokens: u32,
}

#[cfg_attr(feature = "wasm", wasm_bindgen)]
impl DiffResult {
    /// Number of lines added in the new text.
    #[cfg_attr(feature = "wasm", wasm_bindgen(getter))]
    pub fn added_lines(&self) -> u32 {
        self.added_lines
    }
    /// Number of lines removed from the old text.
    #[cfg_attr(feature = "wasm", wasm_bindgen(getter))]
    pub fn removed_lines(&self) -> u32 {
        self.removed_lines
    }
    /// Estimated tokens added.
    #[cfg_attr(feature = "wasm", wasm_bindgen(getter))]
    pub fn added_tokens(&self) -> u32 {
        self.added_tokens
    }
    /// Estimated tokens removed.
    #[cfg_attr(feature = "wasm", wasm_bindgen(getter))]
    pub fn removed_tokens(&self) -> u32 {
        self.removed_tokens
    }
}

/// Build the LCS DP table for two line arrays.
fn build_lcs_table(old_lines: &[&str], new_lines: &[&str]) -> Vec<Vec<u32>> {
    let n = old_lines.len();
    let m = new_lines.len();
    let mut dp = vec![vec![0u32; m + 1]; n + 1];
    for i in 1..=n {
        for j in 1..=m {
            if old_lines[i - 1] == new_lines[j - 1] {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            } else {
                dp[i][j] = dp[i - 1][j].max(dp[i][j - 1]);
            }
        }
    }
    dp
}

/// Compute a line-based diff between two texts.
///
/// Uses a hash-based LCS (Longest Common Subsequence) approach for
/// O(n*m) comparison where n and m are line counts. Returns counts
/// of added/removed lines and estimated token impact.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn compute_diff(old_text: &str, new_text: &str) -> DiffResult {
    let old_lines: Vec<&str> = old_text.lines().collect();
    let new_lines: Vec<&str> = new_text.lines().collect();

    let n = old_lines.len();
    let m = new_lines.len();
    let dp = build_lcs_table(&old_lines, &new_lines);

    // Backtrack to find which lines were removed and which were added
    let mut removed = Vec::new();
    let mut added = Vec::new();
    let mut i = n;
    let mut j = m;

    while i > 0 || j > 0 {
        if i > 0 && j > 0 && old_lines[i - 1] == new_lines[j - 1] {
            i -= 1;
            j -= 1;
        } else if j > 0 && (i == 0 || dp[i][j - 1] >= dp[i - 1][j]) {
            added.push(new_lines[j - 1]);
            j -= 1;
        } else {
            removed.push(old_lines[i - 1]);
            i -= 1;
        }
    }

    let added_tokens: u32 = added.iter().map(|l| calculate_tokens(l)).sum();
    let removed_tokens: u32 = removed.iter().map(|l| calculate_tokens(l)).sum();

    DiffResult {
        added_lines: added.len() as u32,
        removed_lines: removed.len() as u32,
        added_tokens,
        removed_tokens,
    }
}

// ── Structured Diff ────────────────────────────────────────────

/// A single line in a structured diff, with type and line numbers.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct StructuredDiffLine {
    /// "context", "added", or "removed".
    #[serde(rename = "type")]
    pub line_type: String,
    /// The text content of the line.
    pub content: String,
    /// Line number in the old text (null for added lines).
    #[serde(rename = "oldLine")]
    pub old_line: Option<u32>,
    /// Line number in the new text (null for removed lines).
    #[serde(rename = "newLine")]
    pub new_line: Option<u32>,
}

/// Full structured diff result with lines and summary counts.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct StructuredDiffResult {
    /// Interleaved diff lines with types and line numbers.
    pub lines: Vec<StructuredDiffLine>,
    /// Number of added lines.
    #[serde(rename = "addedLineCount")]
    pub added_line_count: u32,
    /// Number of removed lines.
    #[serde(rename = "removedLineCount")]
    pub removed_line_count: u32,
    /// Estimated tokens added.
    #[serde(rename = "addedTokens")]
    pub added_tokens: u32,
    /// Estimated tokens removed.
    #[serde(rename = "removedTokens")]
    pub removed_tokens: u32,
}

/// Compute a structured line-level diff between two texts.
///
/// Returns a JSON-serialized [`StructuredDiffResult`] with interleaved
/// context, added, and removed lines including line numbers for both
/// old and new text. This is the single source of truth for diff display.
///
/// Uses the same LCS algorithm as [`compute_diff`] but produces full
/// line-by-line output instead of just counts.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn structured_diff(old_text: &str, new_text: &str) -> String {
    let result = structured_diff_native(old_text, new_text);
    serde_json::to_string(&result).unwrap_or_else(|_| {
        r#"{"lines":[],"addedLineCount":0,"removedLineCount":0,"addedTokens":0,"removedTokens":0}"#
            .to_string()
    })
}

/// Native version of [`structured_diff`] returning a typed struct.
pub fn structured_diff_native(old_text: &str, new_text: &str) -> StructuredDiffResult {
    let old_lines: Vec<&str> = old_text.lines().collect();
    let new_lines: Vec<&str> = new_text.lines().collect();

    let n = old_lines.len();
    let m = new_lines.len();
    let dp = build_lcs_table(&old_lines, &new_lines);

    // Backtrack from bottom-right, collecting entries in reverse
    let mut entries: Vec<StructuredDiffLine> = Vec::new();
    let mut i = n;
    let mut j = m;

    while i > 0 || j > 0 {
        if i > 0 && j > 0 && old_lines[i - 1] == new_lines[j - 1] {
            entries.push(StructuredDiffLine {
                line_type: "context".to_string(),
                content: old_lines[i - 1].to_string(),
                old_line: Some(i as u32),
                new_line: Some(j as u32),
            });
            i -= 1;
            j -= 1;
        } else if j > 0 && (i == 0 || dp[i][j - 1] >= dp[i - 1][j]) {
            entries.push(StructuredDiffLine {
                line_type: "added".to_string(),
                content: new_lines[j - 1].to_string(),
                old_line: None,
                new_line: Some(j as u32),
            });
            j -= 1;
        } else {
            entries.push(StructuredDiffLine {
                line_type: "removed".to_string(),
                content: old_lines[i - 1].to_string(),
                old_line: Some(i as u32),
                new_line: None,
            });
            i -= 1;
        }
    }

    // Reverse to get forward order
    entries.reverse();

    // Compute summary counts
    let mut added_count: u32 = 0;
    let mut removed_count: u32 = 0;
    let mut added_tokens: u32 = 0;
    let mut removed_tokens: u32 = 0;

    for entry in &entries {
        match entry.line_type.as_str() {
            "added" => {
                added_count += 1;
                added_tokens += calculate_tokens(&entry.content);
            }
            "removed" => {
                removed_count += 1;
                removed_tokens += calculate_tokens(&entry.content);
            }
            _ => {}
        }
    }

    StructuredDiffResult {
        lines: entries,
        added_line_count: added_count,
        removed_line_count: removed_count,
        added_tokens,
        removed_tokens,
    }
}

// ── Multi-way Diff ─────────────────────────────────────────────

/// A single version variant at a divergent line position.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct MultiDiffVariant {
    /// 0-based index into the versions array that was passed in.
    #[serde(rename = "versionIndex")]
    pub version_index: usize,
    /// The content this version has at this line position.
    pub content: String,
}

/// One line entry in a multi-way diff result.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct MultiDiffLine {
    /// 1-based position in the padded line grid.
    #[serde(rename = "lineNumber")]
    pub line_number: usize,
    /// "consensus" when all versions agree, "divergent" otherwise.
    #[serde(rename = "type")]
    pub line_type: String,
    /// The most common variant's content (or the unanimous content for consensus lines).
    pub content: String,
    /// How many versions have `content` at this position.
    pub agreement: usize,
    /// Total number of versions (including the base).
    pub total: usize,
    /// All per-version contents when `line_type` is "divergent"; empty for "consensus".
    pub variants: Vec<MultiDiffVariant>,
}

/// Aggregate statistics for a multi-way diff.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct MultiDiffStats {
    #[serde(rename = "totalLines")]
    pub total_lines: usize,
    #[serde(rename = "consensusLines")]
    pub consensus_lines: usize,
    #[serde(rename = "divergentLines")]
    pub divergent_lines: usize,
    #[serde(rename = "consensusPercentage")]
    pub consensus_percentage: f64,
}

/// Full result of a multi-way diff.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct MultiDiffResult {
    /// Index of the base version (always 0, meaning `base` itself).
    #[serde(rename = "baseVersion")]
    pub base_version: usize,
    /// Number of versions compared (base + additional versions).
    #[serde(rename = "versionCount")]
    pub version_count: usize,
    pub lines: Vec<MultiDiffLine>,
    pub stats: MultiDiffStats,
}

/// Compute a multi-way diff across a base version and up to 4 additional versions.
///
/// `base` is the base version content (typically v1).
/// `versions_json` is a JSON array of strings (up to 4 entries) where each string
/// is the full content of an additional version.
///
/// Uses LCS-based alignment via [`structured_diff_native`] so that insertions and
/// deletions in any version do not cause downstream lines to appear divergent.
/// Each base line is an anchor row; lines inserted by versions get their own rows
/// tagged as "insertion".
///
/// Returns a [`MultiDiffResult`] or an error string.
pub fn multi_way_diff_native(base: &str, versions_json: &str) -> Result<MultiDiffResult, String> {
    let additional: Vec<String> =
        serde_json::from_str(versions_json).map_err(|e| format!("Invalid versions JSON: {e}"))?;

    if additional.len() > 4 {
        return Err(format!(
            "Too many versions: got {}, max is 4 additional (5 total)",
            additional.len()
        ));
    }

    let version_count = 1 + additional.len();
    let base_lines: Vec<&str> = base.lines().collect();

    if base_lines.is_empty() && additional.iter().all(|v| v.is_empty()) {
        return Ok(MultiDiffResult {
            base_version: 0,
            version_count,
            lines: vec![],
            stats: MultiDiffStats {
                total_lines: 0,
                consensus_lines: 0,
                divergent_lines: 0,
                consensus_percentage: 100.0,
            },
        });
    }

    let n_base = base_lines.len();
    let alignments: Vec<crate::diff_multi::VersionAlignment> = additional
        .iter()
        .map(|v| crate::diff_multi::align_version(base, v.as_str(), n_base))
        .collect();

    let grid = crate::diff_multi::build_aligned_grid(&base_lines, &alignments, version_count);
    let (lines, stats) = crate::diff_multi::score_grid(&grid, version_count);

    Ok(MultiDiffResult {
        base_version: 0,
        version_count,
        lines,
        stats,
    })
}

/// JSON-returning wrapper for [`multi_way_diff_native`].
///
/// On success returns a JSON-serialised [`MultiDiffResult`].
/// On error returns `{"error": "<message>"}`.
pub fn multi_way_diff(base: &str, versions_json: &str) -> String {
    match multi_way_diff_native(base, versions_json) {
        Ok(result) => serde_json::to_string(&result)
            .unwrap_or_else(|e| format!(r#"{{"error":"serialization failed: {e}"}}"#)),
        Err(e) => format!(r#"{{"error":{}}}"#, serde_json::json!(e)),
    }
}

