        let base = "alpha\nbeta\ngamma";
        let v1 = "alpha\nBETA\ngamma";
        let v2 = "alpha\nBETA\ngamma";
        let versions_json = serde_json::to_string(&vec![v1, v2]).unwrap();
        let result = multi_way_diff_native(base, &versions_json).unwrap();

