//! Document lifecycle state machine.
//!
//! Defines the allowed states for collaborative documents and validates
//! transitions between them. All functions are pure.

#[cfg(feature = "wasm")]
use wasm_bindgen::prelude::*;

/// Lifecycle state of a collaborative document.
///
/// Matches the TypeScript `DocumentState` type exactly.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum DocumentState {
    Draft = 0,
    Review = 1,
    Locked = 2,
    Archived = 3,
}

impl DocumentState {
    /// Parse a state from its string representation (case-insensitive).
    pub fn from_str_name(s: &str) -> Option<Self> {
        match s.to_uppercase().as_str() {
            "DRAFT" => Some(Self::Draft),
            "REVIEW" => Some(Self::Review),
            "LOCKED" => Some(Self::Locked),
            "ARCHIVED" => Some(Self::Archived),
            _ => None,
        }
    }

    /// Return the canonical uppercase string name.
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Draft => "DRAFT",
            Self::Review => "REVIEW",
            Self::Locked => "LOCKED",
            Self::Archived => "ARCHIVED",
        }
    }

    /// Return the allowed transition targets from this state.
    pub fn allowed_targets(&self) -> &'static [DocumentState] {
        match self {
            Self::Draft => &[Self::Review, Self::Locked],
            Self::Review => &[Self::Draft, Self::Locked],
            Self::Locked => &[Self::Archived],
            Self::Archived => &[],
        }
    }
}

impl std::fmt::Display for DocumentState {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(self.as_str())
    }
}

/// Check whether a state transition is allowed.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn is_valid_transition(from: DocumentState, to: DocumentState) -> bool {
    from.allowed_targets().contains(&to)
}

/// Check whether a document state allows content modifications.
///
/// Only DRAFT and REVIEW states accept new versions/patches.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn is_editable(state: DocumentState) -> bool {
    matches!(state, DocumentState::Draft | DocumentState::Review)
}

/// Check whether a document state is terminal (no further transitions).
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn is_terminal(state: DocumentState) -> bool {
    state.allowed_targets().is_empty()
}

// ── WASM string helpers ────────────────────────────────────────

/// Parse a state string and check if the transition is valid.
/// Accepts uppercase state names ("DRAFT", "REVIEW", etc.).
/// Returns false for unrecognized state names.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn is_valid_transition_str(from: &str, to: &str) -> bool {
    match (
        DocumentState::from_str_name(from),
        DocumentState::from_str_name(to),
    ) {
        (Some(f), Some(t)) => is_valid_transition(f, t),
        _ => false,
    }
}

/// Parse a state string and check if it's editable.
/// Returns false for unrecognized state names.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn is_editable_str(state: &str) -> bool {
    DocumentState::from_str_name(state).is_some_and(is_editable)
}

/// Parse a state string and check if it's terminal.
/// Returns false for unrecognized state names.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn is_terminal_str(state: &str) -> bool {
    DocumentState::from_str_name(state).is_some_and(is_terminal)
}

/// Validate a proposed transition and return a JSON result.
///
/// Returns a JSON object with `valid`, `reason`, and `allowedTargets` fields.
/// Matches the TypeScript `TransitionResult` interface.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn validate_transition(from: &str, to: &str) -> String {
    let from_state = match DocumentState::from_str_name(from) {
        Some(s) => s,
        None => {
            return serde_json::json!({
                "valid": false,
                "reason": format!("Unknown state: {from}"),
                "allowedTargets": []
            })
            .to_string();
        }
    };

    let to_state = match DocumentState::from_str_name(to) {
        Some(s) => s,
        None => {
            return serde_json::json!({
                "valid": false,
                "reason": format!("Unknown state: {to}"),
                "allowedTargets": from_state.allowed_targets().iter().map(|s| s.as_str()).collect::<Vec<_>>()
            })
            .to_string();
        }
    };

    let allowed: Vec<&str> = from_state
        .allowed_targets()
        .iter()
        .map(|s| s.as_str())
        .collect();

    if from_state == to_state {
        return serde_json::json!({
            "valid": false,
            "reason": format!("Document is already in {} state", from_state),
            "allowedTargets": allowed
        })
        .to_string();
    }

    if !is_valid_transition(from_state, to_state) {
        let allowed_str = if allowed.is_empty() {
            "none (terminal state)".to_string()
        } else {
            allowed.join(", ")
        };
        return serde_json::json!({
            "valid": false,
            "reason": format!("Cannot transition from {} to {}. Allowed: {}", from_state, to_state, allowed_str),
            "allowedTargets": allowed
        })
        .to_string();
    }

    serde_json::json!({
        "valid": true,
        "allowedTargets": allowed
    })
    .to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_valid_transitions() {
        assert!(is_valid_transition(
            DocumentState::Draft,
            DocumentState::Review
        ));
        assert!(is_valid_transition(
            DocumentState::Draft,
            DocumentState::Locked
        ));
        assert!(is_valid_transition(
            DocumentState::Review,
            DocumentState::Draft
        ));
        assert!(is_valid_transition(
            DocumentState::Review,
            DocumentState::Locked
        ));
        assert!(is_valid_transition(
            DocumentState::Locked,
            DocumentState::Archived
        ));
    }

    #[test]
    fn test_invalid_transitions() {
        assert!(!is_valid_transition(
            DocumentState::Draft,
            DocumentState::Archived
        ));
        assert!(!is_valid_transition(
            DocumentState::Review,
            DocumentState::Archived
        ));
        assert!(!is_valid_transition(
            DocumentState::Locked,
            DocumentState::Draft
        ));
        assert!(!is_valid_transition(
            DocumentState::Locked,
            DocumentState::Review
        ));
        assert!(!is_valid_transition(
            DocumentState::Archived,
            DocumentState::Draft
        ));
        assert!(!is_valid_transition(
            DocumentState::Archived,
            DocumentState::Review
        ));
        assert!(!is_valid_transition(
            DocumentState::Archived,
            DocumentState::Locked
        ));
    }

    #[test]
    fn test_self_transitions_invalid() {
        assert!(!is_valid_transition(
            DocumentState::Draft,
            DocumentState::Draft
        ));
        assert!(!is_valid_transition(
            DocumentState::Review,
            DocumentState::Review
        ));
        assert!(!is_valid_transition(
            DocumentState::Locked,
            DocumentState::Locked
        ));
        assert!(!is_valid_transition(
            DocumentState::Archived,
            DocumentState::Archived
        ));
    }

    #[test]
    fn test_editable() {
        assert!(is_editable(DocumentState::Draft));
        assert!(is_editable(DocumentState::Review));
        assert!(!is_editable(DocumentState::Locked));
        assert!(!is_editable(DocumentState::Archived));
    }

    #[test]
    fn test_terminal() {
        assert!(!is_terminal(DocumentState::Draft));
        assert!(!is_terminal(DocumentState::Review));
        assert!(!is_terminal(DocumentState::Locked));
        assert!(is_terminal(DocumentState::Archived));
    }

    #[test]
    fn test_string_helpers() {
        assert!(is_valid_transition_str("DRAFT", "REVIEW"));
        assert!(is_valid_transition_str("draft", "review")); // case-insensitive
        assert!(!is_valid_transition_str("DRAFT", "ARCHIVED"));
        assert!(!is_valid_transition_str("DRAFT", "UNKNOWN"));
        assert!(!is_valid_transition_str("UNKNOWN", "DRAFT"));
    }

    #[test]
    fn test_editable_str() {
        assert!(is_editable_str("DRAFT"));
        assert!(is_editable_str("REVIEW"));
        assert!(!is_editable_str("LOCKED"));
        assert!(!is_editable_str("ARCHIVED"));
        assert!(!is_editable_str("UNKNOWN"));
    }

    #[test]
    fn test_terminal_str() {
        assert!(!is_terminal_str("DRAFT"));
        assert!(is_terminal_str("ARCHIVED"));
        assert!(!is_terminal_str("UNKNOWN"));
    }

    #[test]
    fn test_validate_transition_json() {
        let result: serde_json::Value =
            serde_json::from_str(&validate_transition("DRAFT", "REVIEW")).unwrap();
        assert_eq!(result["valid"], true);

        let result: serde_json::Value =
            serde_json::from_str(&validate_transition("DRAFT", "ARCHIVED")).unwrap();
        assert_eq!(result["valid"], false);
        assert!(
            result["reason"]
                .as_str()
                .unwrap()
                .contains("Cannot transition")
        );

        let result: serde_json::Value =
            serde_json::from_str(&validate_transition("DRAFT", "DRAFT")).unwrap();
        assert_eq!(result["valid"], false);
        assert!(result["reason"].as_str().unwrap().contains("already in"));

        let result: serde_json::Value =
            serde_json::from_str(&validate_transition("ARCHIVED", "DRAFT")).unwrap();
        assert_eq!(result["valid"], false);
        assert!(result["reason"].as_str().unwrap().contains("terminal"));
    }

    #[test]
    fn test_from_str_name() {
        assert_eq!(
            DocumentState::from_str_name("DRAFT"),
            Some(DocumentState::Draft)
        );
        assert_eq!(
            DocumentState::from_str_name("draft"),
            Some(DocumentState::Draft)
        );
        assert_eq!(
            DocumentState::from_str_name("Draft"),
            Some(DocumentState::Draft)
        );
        assert_eq!(
            DocumentState::from_str_name("REVIEW"),
            Some(DocumentState::Review)
        );
        assert_eq!(
            DocumentState::from_str_name("LOCKED"),
            Some(DocumentState::Locked)
        );
        assert_eq!(
            DocumentState::from_str_name("ARCHIVED"),
            Some(DocumentState::Archived)
        );
        assert_eq!(DocumentState::from_str_name("unknown"), None);
    }
}

use crate::compute_signature_with_length;

/// Parameters extracted from a verified signed URL.
#[derive(Debug)]
pub struct SignedUrlParams {
    /// Document slug.
    pub slug: String,
    /// Agent that was granted access.
    pub agent_id: String,
    /// Conversation scope.
    pub conversation_id: String,
    /// Expiration timestamp in milliseconds.
    pub expires_at: u64,
}

/// Errors that can occur during signed URL verification.
#[derive(Debug)]
pub enum VerifyError {
    /// Required query parameters are missing or malformed.
    MissingParams,
    /// The URL has expired.
    Expired,
    /// The HMAC signature does not match.
    InvalidSignature,
}

/// Input for generating a signed URL in native Rust consumers.
pub struct SignedUrlBuildRequest<'a> {
    /// Base API origin such as `https://api.example.com`.
    pub base_url: &'a str,
    /// Optional resource path prefix such as `attachments`.
    pub path_prefix: &'a str,
    /// Document slug.
    pub slug: &'a str,
    /// Agent that is granting access.
    pub agent_id: &'a str,
    /// Conversation scope.
    pub conversation_id: &'a str,
    /// Expiration timestamp in milliseconds.
    pub expires_at: u64,
    /// Signing secret.
    pub secret: &'a str,
    /// Signature length in hex characters.
    pub sig_length: usize,
}

/// Generate a signed URL with an optional resource path prefix. Native Rust API only.
///
/// Use `path_prefix` such as `"attachments"` to produce
/// `https://host/attachments/{slug}?agent=...`.
///
/// # Errors
/// Returns an error string if `base_url` is invalid.
pub fn generate_signed_url(request: &SignedUrlBuildRequest<'_>) -> Result<String, String> {
    let mut url =
        url::Url::parse(request.base_url).map_err(|e| format!("invalid base url: {e}"))?;
    let normalized_prefix = request.path_prefix.trim_matches('/');
    let path = if normalized_prefix.is_empty() {
        format!("/{}", request.slug)
    } else {
        format!("/{normalized_prefix}/{}", request.slug)
    };
    url.set_path(&path);

    let signature = compute_signature_with_length(
        request.slug,
        request.agent_id,
        request.conversation_id,
        request.expires_at as f64,
        request.secret,
        request.sig_length,
    );

    url.query_pairs_mut()
        .append_pair("agent", request.agent_id)
        .append_pair("conv", request.conversation_id)
        .append_pair("exp", &request.expires_at.to_string())
        .append_pair("sig", &signature);

    Ok(url.into())
}

/// Verify a signed URL. Native Rust API only.
///
/// # Errors
/// Returns `VerifyError` if the URL is invalid, expired, or has a bad signature.
pub fn verify_signed_url(input: &str, secret: &str) -> Result<SignedUrlParams, VerifyError> {
    let parsed = url::Url::parse(input).map_err(|_| VerifyError::MissingParams)?;

    let slug = parsed
        .path_segments()
        .and_then(|mut segments| segments.rfind(|segment| !segment.is_empty()))
        .map(str::to_string)
        .ok_or(VerifyError::MissingParams)?;

    let get_param = |name: &str| -> Result<String, VerifyError> {
        parsed
            .query_pairs()
            .find(|(k, _)| k == name)
            .map(|(_, v)| v.to_string())
            .ok_or(VerifyError::MissingParams)
    };

    let agent = get_param("agent")?;
    let conv = get_param("conv")?;
    let exp_str = get_param("exp")?;
    let sig = get_param("sig")?;

    let expires_at: u64 = exp_str.parse().map_err(|_| VerifyError::MissingParams)?;

    let now = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_millis() as u64)
        .unwrap_or(0);
    if expires_at != 0 && now > expires_at {
        return Err(VerifyError::Expired);
    }

    let expected =
        compute_signature_with_length(&slug, &agent, &conv, expires_at as f64, secret, sig.len());
    if sig != expected {
        return Err(VerifyError::InvalidSignature);
    }

    Ok(SignedUrlParams {
        slug,
        agent_id: agent,
        conversation_id: conv,
        expires_at,
    })
}

use diffy::{Patch, apply as diffy_apply, create_patch as diffy_create_patch};

#[cfg(feature = "wasm")]
use wasm_bindgen::prelude::*;

use crate::{DiffResult, compute_diff};

/// Apply a unified diff patch to an original string.
/// Returns the updated string on success, or an error if the patch is invalid
/// or fails to apply cleanly.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn apply_patch(original: &str, patch_text: &str) -> Result<String, String> {
    let patch = Patch::from_str(patch_text).map_err(|err| format!("Invalid patch text: {err}"))?;
    diffy_apply(original, &patch).map_err(|err| format!("Patch application failed: {err}"))
}

/// Create a unified diff patch representing the difference between `original`
/// and `modified`.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn create_patch(original: &str, modified: &str) -> String {
    diffy_create_patch(original, modified).to_string()
}

/// Apply a sequence of patches to base content, returning the content at the
/// target version. This avoids N WASM boundary crossings by performing all
/// patch applications in a single Rust call.
///
/// `patches_json` is a JSON array of patch strings: `["patch1", "patch2", ...]`.
/// `target` is the 1-based version to reconstruct (0 returns `base` unchanged).
/// If `target` exceeds the number of patches, all patches are applied.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn reconstruct_version(base: &str, patches_json: &str, target: u32) -> Result<String, String> {
    if target == 0 {
        return Ok(base.to_string());
    }

    let patches: Vec<String> =
        serde_json::from_str(patches_json).map_err(|e| format!("Invalid patches JSON: {e}"))?;

    let limit = (target as usize).min(patches.len());
    let mut content = base.to_string();

    for (i, patch_text) in patches.iter().take(limit).enumerate() {
        content = apply_patch(&content, patch_text)
            .map_err(|e| format!("Patch {} failed: {e}", i + 1))?;
    }

    Ok(content)
}

/// Native-friendly version of [`reconstruct_version`] that accepts a slice
/// directly instead of JSON. Use this from Rust consumers; the JSON variant
/// is for WASM callers.
pub fn reconstruct_version_native(
    base: &str,
    patches: &[String],
    target: usize,
) -> Result<String, String> {
    if target == 0 {
        return Ok(base.to_string());
    }
    let limit = target.min(patches.len());
    let mut content = base.to_string();
    for (i, patch_text) in patches.iter().take(limit).enumerate() {
        content = apply_patch(&content, patch_text)
            .map_err(|e| format!("Patch {} failed: {e}", i + 1))?;
    }
    Ok(content)
}

/// Native-friendly version of [`squash_patches`] that accepts a slice directly.
pub fn squash_patches_native(base: &str, patches: &[String]) -> Result<String, String> {
    let final_content = reconstruct_version_native(base, patches, patches.len())?;
    Ok(create_patch(base, &final_content))
}

/// Apply all patches sequentially to base content, then produce a single
/// unified diff from the original base to the final state.
///
/// `patches_json` is a JSON array of patch strings: `["patch1", "patch2", ...]`.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn squash_patches(base: &str, patches_json: &str) -> Result<String, String> {
    let patches: Vec<String> =
        serde_json::from_str(patches_json).map_err(|e| format!("Invalid patches JSON: {e}"))?;

    let mut content = base.to_string();
    for (i, patch_text) in patches.iter().enumerate() {
        content = apply_patch(&content, patch_text)
            .map_err(|e| format!("Patch {} failed: {e}", i + 1))?;
    }

    Ok(create_patch(base, &content))
}

// ── Version Diff ──────────────────────────────────────────────

/// Reconstruct two versions and compute a diff between them.
///
/// Returns a JSON string with `fromVersion`, `toVersion`, `addedLines`,
/// `removedLines`, `addedTokens`, `removedTokens`, and `patchText` fields.
/// Matches the TypeScript `VersionDiffSummary` interface.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn diff_versions(
    base: &str,
    patches_json: &str,
    from_version: u32,
    to_version: u32,
) -> Result<String, String> {
    let patches: Vec<String> =
        serde_json::from_str(patches_json).map_err(|e| format!("Invalid patches JSON: {e}"))?;
    let (diff, patch_text) =
        diff_versions_native(base, &patches, from_version as usize, to_version as usize)?;

    Ok(serde_json::json!({
        "fromVersion": from_version,
        "toVersion": to_version,
        "addedLines": diff.added_lines(),
        "removedLines": diff.removed_lines(),
        "addedTokens": diff.added_tokens(),
        "removedTokens": diff.removed_tokens(),
        "patchText": patch_text
    })
    .to_string())
}

/// Native version of [`diff_versions`] that accepts a slice and returns a struct.
pub fn diff_versions_native(
    base: &str,
    patches: &[String],
    from_version: usize,
    to_version: usize,
) -> Result<(DiffResult, String), String> {
    let from_content = reconstruct_version_native(base, patches, from_version)?;
    let to_content = reconstruct_version_native(base, patches, to_version)?;
    let diff = compute_diff(&from_content, &to_content);
    let patch_text = create_patch(&from_content, &to_content);
    Ok((diff, patch_text))
}

/// Compare multiple versions against a base version in a single call.
///
/// `version_numbers` is a JSON array of version numbers to compare: `[1, 3, 5, 8]`.
/// Each is reconstructed from the patch chain and diffed against `base_version`.
/// Returns a JSON array of diff results.
///
/// This avoids N separate WASM calls and parses the patches JSON once.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn batch_diff_versions(
    base: &str,
    patches_json: &str,
    base_version: u32,
    version_numbers_json: &str,
) -> Result<String, String> {
    let patches: Vec<String> =
        serde_json::from_str(patches_json).map_err(|e| format!("Invalid patches JSON: {e}"))?;
    let version_numbers: Vec<u32> = serde_json::from_str(version_numbers_json)
        .map_err(|e| format!("Invalid version numbers JSON: {e}"))?;

    let base_content = reconstruct_version_native(base, &patches, base_version as usize)?;
    let mut results = Vec::new();

    for &ver in &version_numbers {
        if ver == base_version {
            continue;
        }
        let ver_content = reconstruct_version_native(base, &patches, ver as usize)?;
        let diff = compute_diff(&base_content, &ver_content);
        let patch_text = create_patch(&base_content, &ver_content);

        results.push(serde_json::json!({
            "fromVersion": base_version,
            "toVersion": ver,
            "addedLines": diff.added_lines(),
            "removedLines": diff.removed_lines(),
            "addedTokens": diff.added_tokens(),
            "removedTokens": diff.removed_tokens(),
            "patchText": patch_text,
        }));
    }

    serde_json::to_string(&results).map_err(|e| format!("Serialization failed: {e}"))
}

// ── Section Change Detection ──────────────────────────────────

/// Split content into sections keyed by their heading name.
/// Lines before the first heading go under "".
fn sections_map(content: &str) -> std::collections::HashMap<String, String> {
    let mut map = std::collections::HashMap::new();
    let mut current_heading = String::new();
    let mut current_lines: Vec<&str> = Vec::new();

    for line in content.lines() {
        let trimmed = line.trim();
        if trimmed.starts_with('#') {
            // Save previous section
            if !current_lines.is_empty() || !current_heading.is_empty() {
                map.insert(current_heading.clone(), current_lines.join("\n"));
            }
            current_heading = trimmed.trim_start_matches('#').trim().to_string();
            current_lines = Vec::new();
        } else {
            current_lines.push(line);
        }
    }
    // Save last section
    map.insert(current_heading, current_lines.join("\n"));
    map
}

/// Compute which markdown sections were modified between two document versions.
///
/// Returns a JSON array of section heading names that changed.
/// Detects added, removed, and modified sections.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn compute_sections_modified(old_content: &str, new_content: &str) -> String {
    let result = compute_sections_modified_native(old_content, new_content);
    serde_json::to_string(&result).unwrap_or_else(|_| "[]".to_string())
}

/// Native version returning a `Vec<String>` of modified section names.
pub fn compute_sections_modified_native(old_content: &str, new_content: &str) -> Vec<String> {
    let old_sections = sections_map(old_content);
    let new_sections = sections_map(new_content);

    let mut modified = Vec::new();

    // Check for modified or removed sections
    for (name, old_body) in &old_sections {
        match new_sections.get(name) {
            Some(new_body) if new_body != old_body => {
                if !name.is_empty() {
                    modified.push(name.clone());
                }
            }
            None => {
                if !name.is_empty() {
                    modified.push(name.clone());
                }
            }
            _ => {}
        }
    }

    // Check for new sections
    for name in new_sections.keys() {
        if !name.is_empty() && !old_sections.contains_key(name) {
            modified.push(name.clone());
        }
    }

    modified.sort();
    modified
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_create_and_apply_patch() {
        let original = "Hello world. This is a test.\n";
        let modified = "Hello beautiful world. This is an awesome test.\n";

        let patch = create_patch(original, modified);
        assert!(patch.contains("@@"));

        let applied = apply_patch(original, &patch).expect("patch should apply");
        assert_eq!(applied, modified);
    }

    #[test]
    fn test_apply_invalid_patch() {
        let result = apply_patch("Hello world\n", "@@ invalid patch format @@");
        assert!(result.is_err());
    }

    #[test]
    fn test_reconstruct_version_zero_returns_base() {
        let base = "Hello world\n";
        let result = reconstruct_version(base, "[]", 0).unwrap();
        assert_eq!(result, base);
    }

    #[test]
    fn test_reconstruct_version_applies_patches() {
        let v0 = "line 1\n";
        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nline 2\nline 3\n";

        let p1 = create_patch(v0, v1);
        let p2 = create_patch(v1, v2);
        let patches_json = serde_json::to_string(&vec![p1, p2]).unwrap();

        let at_v1 = reconstruct_version(v0, &patches_json, 1).unwrap();
        assert_eq!(at_v1, v1);

        let at_v2 = reconstruct_version(v0, &patches_json, 2).unwrap();
        assert_eq!(at_v2, v2);
    }

    #[test]
    fn test_squash_patches_produces_single_diff() {
        let v0 = "line 1\n";
        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nline 2\nline 3\n";

        let p1 = create_patch(v0, v1);
        let p2 = create_patch(v1, v2);
        let patches_json = serde_json::to_string(&vec![p1, p2]).unwrap();

        let squashed = squash_patches(v0, &patches_json).unwrap();
        let result = apply_patch(v0, &squashed).unwrap();
        assert_eq!(result, v2);
    }

    #[test]
    fn test_reconstruct_version_native() {
        let v0 = "line 1\n";
        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nline 2\nline 3\n";

        let patches = vec![create_patch(v0, v1), create_patch(v1, v2)];
        let at_v2 = reconstruct_version_native(v0, &patches, 2).unwrap();
        assert_eq!(at_v2, v2);
    }

    #[test]
    fn test_squash_patches_native() {
        let v0 = "line 1\n";
        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nline 2\nline 3\n";

        let patches = vec![create_patch(v0, v1), create_patch(v1, v2)];
        let squashed = squash_patches_native(v0, &patches).unwrap();
        let result = apply_patch(v0, &squashed).unwrap();
        assert_eq!(result, v2);
    }

    #[test]
    fn test_apply_conflicting_patch() {
        let original = "Hello world. This is a test.\n";
        let modified = "Hello beautiful world. This is an awesome test.\n";
        let patch = create_patch(original, modified);

        let result = apply_patch("Completely different text\n", &patch);
        assert!(result.is_err());
    }

    #[test]
    fn test_diff_versions() {
        let v0 = "line 1\n";
        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nline 2\nline 3\n";

        let p1 = create_patch(v0, v1);
        let p2 = create_patch(v1, v2);
        let patches_json = serde_json::to_string(&vec![p1, p2]).unwrap();

        let result_json = diff_versions(v0, &patches_json, 0, 2).unwrap();
        let result: serde_json::Value = serde_json::from_str(&result_json).unwrap();
        assert_eq!(result["fromVersion"], 0);
        assert_eq!(result["toVersion"], 2);
        assert_eq!(result["addedLines"], 2);
        assert_eq!(result["removedLines"], 0);
    }

    #[test]
    fn test_diff_versions_between_non_zero() {
        let v0 = "line 1\n";
        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nmodified 2\nline 3\n";

        let p1 = create_patch(v0, v1);
        let p2 = create_patch(v1, v2);
        let patches_json = serde_json::to_string(&vec![p1, p2]).unwrap();

        let result_json = diff_versions(v0, &patches_json, 1, 2).unwrap();
        let result: serde_json::Value = serde_json::from_str(&result_json).unwrap();
        assert_eq!(result["fromVersion"], 1);
        assert_eq!(result["toVersion"], 2);
        // "line 2" removed, "modified 2" and "line 3" added
        assert!(result["addedLines"].as_u64().unwrap() > 0);
    }

    #[test]
    fn test_compute_sections_modified_basic() {
        let old = "# Intro\nHello world\n# Details\nSome details\n";
        let new = "# Intro\nHello world\n# Details\nModified details\n";

        let result = compute_sections_modified_native(old, new);
        assert_eq!(result, vec!["Details"]);
    }

    #[test]
    fn test_compute_sections_modified_new_section() {
        let old = "# Intro\nHello world\n";
        let new = "# Intro\nHello world\n# New Section\nNew content\n";

        let result = compute_sections_modified_native(old, new);
        assert_eq!(result, vec!["New Section"]);
    }

    #[test]
    fn test_compute_sections_modified_removed_section() {
        let old = "# Intro\nHello world\n# ToRemove\nOld content\n";
        let new = "# Intro\nHello world\n";

        let result = compute_sections_modified_native(old, new);
        assert_eq!(result, vec!["ToRemove"]);
    }

    #[test]
    fn test_compute_sections_modified_no_changes() {
        let content = "# Intro\nHello world\n# Details\nSome details\n";
        let result = compute_sections_modified_native(content, content);
        assert!(result.is_empty());
    }

    #[test]
    fn test_compute_sections_modified_wasm_json() {
        let old = "# A\ntext\n# B\ntext\n";
        let new = "# A\nchanged\n# B\ntext\n";
        let json = compute_sections_modified(old, new);
        let result: Vec<String> = serde_json::from_str(&json).unwrap();
        assert_eq!(result, vec!["A"]);
    }
}
